Steps:
[GQL-OP list_pages]
  query { pages(storeId: "{{STORE_ID}}" keyword: "" first: 10 cultureName: "en-US") { totalCount items { id name relativeUrl permalink } } }
[GQL-EXEC list_pages]

[GQL-OP page_bogus]
  query { page(storeId: "{{STORE_ID}}" id: "{{bogus_id}}" cultureName: "en-US") { id name } }
[GQL-EXEC page_bogus]

[GQL-OP de_pages]
  query { pages(storeId: "{{STORE_ID}}" keyword: "" first: 5 cultureName: "de-DE") { totalCount items { id name } } }
[GQL-EXEC de_pages]

[GQL-OP no_match]
  query { pages(storeId: "{{STORE_ID}}" keyword: "{{no_match_kw}}" first: 10) { totalCount items { id } } }
[GQL-EXEC no_match]

[GQL-OP list_menus]
  query { menus(storeId: "{{STORE_ID}}" cultureName: "en-US") { name outerId items { title url priority } } }
[GQL-EXEC list_menus]

Assertions:
[ERRORS label=one_menu] errors[] empty
[DATA label=one_menu] data.menu is non-null
[DATA label=one_menu] data.menu.name = {{MENU_NAME}}

Steps:
[GQL-OP menu_bogus]
  query { menu(storeId: "{{STORE_ID}}" cultureName: "en-US" name: "{{bogus_name}}") { name outerId } }
[GQL-EXEC menu_bogus]

[GQL-OP ctx_home]
  query { pageContext(storeId: "{{STORE_ID}}" domain: "{{STOREFRONT_DOMAIN}}" userId: "{{TEST_USER_ID}}" permalink: "/" cultureName: "en-US") { store { storeId storeName } slugInfo { redirectUrl entityInfo { objectType id } } user { id userName email memberId } whiteLabelingSettings { footerLinks { title } } } }
[GQL-EXEC ctx_home]

[GQL-OP list_docs]
  query { pageDocuments(storeId: "{{STORE_ID}}" keyword: "" first: 10 cultureName: "en-US") { totalCount items { id title source permalink content } } }
[GQL-EXEC list_docs]

[GQL-OP doc_bogus]
  query { pageDocument(id: "{{bogus_id}}") { id title permalink } }
[GQL-EXEC doc_bogus]

[GQL-OP ctx_catalog]
  query { pageContext(storeId: "{{STORE_ID}}" domain: "{{STOREFRONT_DOMAIN}}" userId: "{{TEST_USER_ID}}" permalink: "/catalog" cultureName: "en-US") { store { storeId storeName } slugInfo { redirectUrl entityInfo { objectType id semanticUrl } } user { id userName memberId } whiteLabelingSettings { footerLinks { title } } } }
[GQL-EXEC ctx_catalog]

[GQL-OP desc_sort]
  query {
    newsArticles(
      storeId: "{{STORE_ID}}"
      languageCode: "en-US"
      sort: "publishDate:desc"
      first: 5
    ) {
      totalCount
      items { id title publishDate }
    }
  }
[GQL-EXEC desc_sort]

[GQL-OP asc_sort]
  query {
    newsArticles(
      storeId: "{{STORE_ID}}"
      languageCode: "en-US"
      sort: "publishDate:asc"
      first: 5
    ) {
      totalCount
      items { id title publishDate }
    }
  }
[GQL-EXEC asc_sort]

[GQL-OP nosort]
  query {
    newsArticles(
      storeId: "{{STORE_ID}}"
      languageCode: "en-US"
      first: 5
    ) {
      totalCount
      items { id title publishDate }
    }
  }
[GQL-EXEC nosort]

[GQL-OP list_pages_health]
  query {
    pages(storeId: "{{STORE_ID}}" keyword: "" first: 5 cultureName: "en-US") {
      totalCount
      items { id name relativeUrl permalink }
    }
  }
[GQL-EXEC list_pages_health]

[GQL-OP list_pages_seed]
  query {
    pages(storeId: "{{STORE_ID}}" keyword: "" first: 1 cultureName: "en-US") {
      items { id name }
    }
  }
[GQL-EXEC list_pages_seed]
[GQL-CAPTURE list_pages_seed.data.pages.items.0.id → CAPTURED_PAGE_ID]
[GQL-OP one_page_post_reindex]
  query {
    page(storeId: "{{STORE_ID}}" id: "{{CAPTURED_PAGE_ID}}" cultureName: "en-US") {
      id name relativeUrl permalink
    }
  }
[GQL-EXEC one_page_post_reindex]

[GQL-OP builder_probe]
  query {
    builderPage(storeId: "{{STORE_ID}}" pageId: "{{bogus_page_id}}") {
      permalink content
    }
  }
[GQL-EXEC builder_probe]
